rc/shared/services/api.js","webpack://wicket_memberships_wp_frontend/./node_modules/moment-timezone/index.js","webpack://wicket_memberships_wp_frontend/./node_modules/moment-timezone/moment-timezone.js","webpack://wicket_memberships_wp_frontend/./node_modules/react-dom/client.js","webpack://wicket_memberships_wp_frontend/external window \"React\"","webpack://wicket_memberships_wp_frontend/external window \"ReactDOM\"","webpack://wicket_memberships_wp_frontend/external window \"moment\"","webpack://wicket_memberships_wp_frontend/external window [\"wp\",\"apiFetch\"]","webpack://wicket_memberships_wp_frontend/external window [\"wp\",\"components\"]","webpack://wicket_memberships_wp_frontend/external window [\"wp\",\"i18n\"]","webpack://wicket_memberships_wp_frontend/external window [\"wp\",\"url\"]","webpack://wicket_memberships_wp_frontend/webpack/bootstrap","webpack://wicket_memberships_wp_frontend/webpack/runtime/compat get default export","webpack://wicket_memberships_wp_frontend/webpack/runtime/define property getters","webpack://wicket_memberships_wp_frontend/webpack/runtime/hasOwnProperty shorthand","webpack://wicket_memberships_wp_frontend/webpack/runtime/make namespace object","webpack://wicket_memberships_wp_frontend/./src/membership_tiers/tier_cell_info.js"],"sourcesContent":["import moment from \"moment-timezone\";\n\nexport const API_URL = \"/wp/v2\";\nexport const WC_API_V3_URL = \"/wc/v3\";\nexport const PLUGIN_API_URL = \"/wicket_member/v1\";\nexport const TIER_CPT_SLUG = \"wicket_mship_tier\";\nexport const DEFAULT_DATE_FORMAT = \"yyyy-MM-dd\";\nexport const WC_PRODUCT_TYPES = [\"subscription\", \"variable-subscription\"];\nexport const PLUGIN_SETTINGS = wicketMembershipsSettings;\nexport const WP_ADMIN_URL = wicketMembershipsSettings.adminUrl;\n\n/**\n * Format a numeric price value as a localized currency string using the\n * currency code from wicketMembershipsSettings (falls back to \"USD\").\n *\n * @param {string|number|null} price\n * @returns {string}\n */\nexport const formatCurrency = (price) => {\n  if (price === undefined || price === null || price === \"\") return \"—\";\n  const num = parseFloat(price);\n  if (isNaN(num)) return price;\n  return new Intl.NumberFormat(undefined, {\n    style: \"currency\",\n    currency: PLUGIN_SETTINGS.currency ?? \"USD\",\n  }).format(num);\n};\n\n/**\n * Format an ISO date string as YYYY-MM-DD with the full ISO 8601 string\n * (in MDP timezone) shown on hover via a title attribute.\n *\n * @param {string} isoString\n * @returns {JSX.Element|string}\n */\nexport const formatDateWithTooltip = (isoString) => {\n  if (!isoString) return \"\";\n  const mdpTimezone = PLUGIN_SETTINGS.WICKET_MSHIP_MDP_TIMEZONE || \"UTC\";\n  const m = moment.tz(isoString, mdpTimezone);\n  const dateDisplay = m.format(\"YYYY-MM-DD\");\n  const isoFull = m.format(); // ISO 8601 with timezone offset, e.g. 2026-10-05T00:00:00-04:00\n  return <span title={isoFull}>{dateDisplay}</span>;\n};\n","import apiFetch from \"@wordpress/api-fetch\";\nimport { addQueryArgs } from \"@wordpress/url\";\nimport {\n  API_URL,\n  PLUGIN_API_URL,\n  TIER_CPT_SLUG,\n  WC_API_V3_URL,\n} from \"../constants\";\n\n/**\n * Fetch Local Membership Tiers Posts\n */\nexport const fetchTiers = () => {\n  return apiFetch({\n    path: addQueryArgs(`${API_URL}/${TIER_CPT_SLUG}`, {\n      status: \"publish\",\n      per_page: 99,\n    }),\n  });\n};\n\n/**\n * Update Membership Record\n */\nexport const updateMembership = (membershipId, data) => {\n  return apiFetch({\n    path: `${PLUGIN_API_URL}/membership_entity/${membershipId}/update`,\n    method: \"POST\",\n    data: data,\n  });\n};\n\n/**\n * Update Membership Status\n */\nexport const updateMembershipStatus = (membershipId, status) => {\n  return apiFetch({\n    path: `${PLUGIN_API_URL}/admin/manage_status`,\n    method: \"POST\",\n    data: {\n      post_id: membershipId,\n      status: status,\n    },\n  });\n};\n\n/**\n * Fetch Membership Records\n */\nexport const fetchMemberships = (recordId = null) => {\n  if (recordId === null) {\n    return;\n  }\n\n  return apiFetch({\n    path: addQueryArgs(`${PLUGIN_API_URL}/membership_entity`, {\n      entity_id: recordId,\n    }),\n  });\n};\n\n/**\n * Fetch Member Info\n */\nexport const fetchMemberInfo = (recordId = null) => {\n  if (recordId === null) {\n    return;\n  }\n\n  return apiFetch({\n    path: addQueryArgs(`${PLUGIN_API_URL}/admin/get_edit_page_info`, {\n      entity_id: recordId,\n    }),\n  });\n};\n\n/**\n * Fetch Available Membership Statuses for a Membership Post\n */\nexport const fetchMembershipStatuses = (postId = null) => {\n  if (postId === null) {\n    return;\n  }\n\n  return apiFetch({\n    path: addQueryArgs(`${PLUGIN_API_URL}/admin/status_options`, {\n      post_id: postId,\n    }),\n  });\n};\n\n/**\n * Fetch Members\n */\nexport const fetchMembers = (params = null) => {\n  if (params === null) {\n    return;\n  }\n\n  return apiFetch({\n    path: addQueryArgs(`${PLUGIN_API_URL}/memberships`, params),\n  });\n};\n\n/**\n * Fetch Group Memberships\n */\nexport const fetchGroupMemberships = (params = null) => {\n  if (params === null) {\n    return;\n  }\n\n  return apiFetch({\n    path: addQueryArgs(`${PLUGIN_API_URL}/group_memberships`, params),\n  });\n};\n\n/**\n * Fetch Membership Tiers Info\n */\nexport const fetchTiersInfo = (tierIds = []) => {\n  if (tierIds.length === 0) {\n    return;\n  }\n\n  return apiFetch({\n    path: addQueryArgs(`${PLUGIN_API_URL}/membership_tier_info`, {\n      filter: {\n        tier_uuid: tierIds,\n      },\n    }),\n  });\n};\n\n/**\n * Fetch Membership Groups Info\n */\nexport const fetchGroupsInfo = (groupIds = []) => {\n  if (groupIds.length === 0) {\n    return;\n  }\n  return apiFetch({\n    path: addQueryArgs(`${PLUGIN_API_URL}/membership_group_info`, {\n      filter: {\n        group_id: groupIds,\n      },\n    }),\n  });\n};\n\n/**\n * Fetch Membership Tiers\n */\nexport const fetchMembershipTiers = (queryParams = {}) => {\n  const url = addQueryArgs(`${PLUGIN_API_URL}/membership_tiers`, queryParams);\n  return apiFetch({ path: url });\n};\n\n/**\n * Fetch MDP Persons\n */\nexport const fetchMdpPersons = (queryParams = {}) => {\n  // ?term=\n  const url = addQueryArgs(`${PLUGIN_API_URL}/mdp_person/search`, queryParams);\n  return apiFetch({ path: url, method: \"POST\" });\n};\n\n/**\n * Fetch group members broken down by tier for a given group post ID.\n * GET /wicket_member/v1/group/{groupPostId}/members_by_tier\n */\nexport const fetchGroupMembersByTier = (groupPostId) => {\n  return apiFetch({\n    path: `${PLUGIN_API_URL}/group/${groupPostId}/members_by_tier`,\n  });\n};\n\n/**\n * Fetch Group Membership Filters\n */\nexport const fetchGroupMembershipFilters = () => {\n  return apiFetch({\n    path: `${PLUGIN_API_URL}/group_membership_filters`,\n  });\n};\n\n/**\n * Fetch Membership Filters\n */\nexport const fetchMembershipFilters = (memberType = null) => {\n  if (memberType === null) {\n    return;\n  }\n\n  return apiFetch({\n    path: addQueryArgs(`${PLUGIN_API_URL}/membership_filters`, {\n      type: memberType,\n    }),\n  });\n};\n\n/**\n * Fetch WooCommerce Products\n */\nexport const fetchWcProducts = (queryParams = {}) => {\n  return apiFetch({\n    path: addQueryArgs(`${WC_API_V3_URL}/products`, queryParams),\n  });\n};\n\n/**\n * Fetch WooCommerce Product Variations\n */\nexport const fetchProductVariations = (productId, queryParams = {}) => {\n  return apiFetch({\n    path: addQueryArgs(\n      `${WC_API_V3_URL}/products/${productId}/variations`,\n      queryParams,\n    ),\n  });\n};\n\n/**\n * Create Renewal Order\n */\nexport const createRenewalOrder = (membershipId, productId, variationId) => {\n  return apiFetch({\n    path: `${PLUGIN_API_URL}/membership/${membershipId}/create_renewal_order`,\n    method: \"POST\",\n    data: {\n      membership_post_id: membershipId,\n      product_id: productId,\n      variation_id: variationId,\n    },\n  });\n};\n\n/**\n * Fetch all data required to populate the group membership detail/edit page.\n *\n * Maps to GET /wicket_member/v1/group/admin/get_edit_page_info?group_post_id=<id>\n *\n * @param {string|number} postId - WP post ID of the membership group.\n */\nexport const fetchGroupEditPageInfo = (postId) => {\n  return apiFetch({\n    path: addQueryArgs(`${PLUGIN_API_URL}/group/admin/get_edit_page_info`, {\n      group_post_id: postId,\n    }),\n  });\n};\n\n/**\n * Fetch available status transition options for a group membership post.\n *\n * Maps to GET /wicket_member/v1/group/admin/status_options?group_post_id=<id>\n *\n * @param {string|number} groupPostId - WP post ID of the membership group.\n */\nexport const fetchGroupMembershipStatuses = (groupPostId = null) => {\n  if (groupPostId === null) {\n    return;\n  }\n\n  return apiFetch({\n    path: addQueryArgs(`${PLUGIN_API_URL}/group/admin/status_options`, {\n      group_post_id: groupPostId,\n    }),\n  });\n};\n\n/**\n * Transition a group membership to a new status.\n *\n * Maps to POST /wicket_member/v1/group/admin/manage_status\n *\n * @param {string|number} groupPostId - WP post ID of the membership group.\n * @param {string}        status      - New status slug.\n */\nexport const updateGroupMembershipStatus = (groupPostId, status) => {\n  return apiFetch({\n    path: `${PLUGIN_API_URL}/group/admin/manage_status`,\n    method: \"POST\",\n    data: {\n      group_post_id: groupPostId,\n      status: status,\n    },\n  });\n};\n\n/**\n * Update editable fields on a group membership post (dates, renewal type, owner).\n *\n * Maps to POST /wicket_member/v1/group_membership_entity/{id}/update\n *\n * @param {string|number} groupPostId - WP post ID of the membership group.\n * @param {object}        data        - Fields to update.\n */\nexport const updateGroupMembership = (groupPostId, data) => {\n  return apiFetch({\n    path: `${PLUGIN_API_URL}/group_membership_entity/${groupPostId}/update`,\n    method