Info Error:\");\n        console.log(error);\n      });\n  }, []);\n\n  return (\n    <>\n      {status === null && <Spinner />}\n      {status !== null && status}\n    </>\n  );\n};\n\n// init multiple instances\nconst app = document.querySelectorAll(\".wicket_memberships_tier_cell_info\");\nif (app) {\n  app.forEach((el) => {\n    createRoot(el).render(<MembershipTierCellInfo {...el.dataset} />);\n  });\n}\n"],"names":["API_URL","WC_API_V3_URL","PLUGIN_API_URL","TIER_CPT_SLUG","DEFAULT_DATE_FORMAT","WC_PRODUCT_TYPES","PLUGIN_SETTINGS","wicketMembershipsSettings","apiFetch","addQueryArgs","fetchTiers","path","status","per_page","updateMembership","membershipId","data","method","updateMembershipStatus","post_id","fetchMemberships","recordId","entity_id","fetchMemberInfo","fetchMembershipStatuses","postId","fetchMembers","params","fetchTiersInfo","tierIds","length","filter","tier_uuid","fetchMembershipTiers","queryParams","url","fetchMdpPersons","fetchMembershipFilters","memberType","type","fetchWcProducts","fetchProductVariations","productId","createRenewalOrder","variationId","membership_post_id","product_id","variation_id","createRoot","useState","useEffect","Spinner","__","MembershipTierCellInfo","tierUuid","tierField","setStatus","filters","id","then","tiers","value","catch","error","console","log","createElement","Fragment","app","document","querySelectorAll","forEach","el","render","dataset"],"sourceRoot":""}
